vi.mock('../../lib/analytics.js', () => ({
  hashProject: vi.fn(() => 'abc123hash'),
}));

vi.mock('../../lib/paths.js', () => ({
  getMetricsFile: vi.fn(() => '/tmp/metrics.json'),
  getHomeDir: vi.fn(() => '/home/test'),
  joinPath: (...args: string[]) => args.join('/'),
}));

import { sessionHandoffGenerator } from '../../lifecycle/session-handoff-generator.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'SessionEnd',
    tool_name: '',
    session_id: 'test-session-001',
    tool_input: {},
    project_dir: '/test/project',
    ...overrides,
  };
}

function getLatestYaml(): string {
  // Find the latest.yaml write call
  const calls = mockWriteFileSync.mock.calls as [string, string, string][];
  const latestCall = calls.find(c => String(c[0]).includes('latest.yaml'));
  return latestCall ? latestCall[1] : '';
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('lifecycle/session-handoff-generator', () => {
  beforeEach(() => {
    vi.resetAllMocks();
    mockExistsSync.mockReturnValue(false);
    mockReadFileSync.mockReturnValue('{}');
    mockExecSync.mockReturnValue('');
    mockReaddirSync.mockReturnValue([]);
  });

  describe('always returns silent success', () => {
    it('returns { continue: true, suppressOutput: true }', () => {
      const result = sessionHandoffGenerator(createInput());
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    it('returns silent success even when write throws', () => {
      mockWriteFileSync.mockImplementation(() => { throw new Error('disk full'); });
      const result = sessionHandoffGenerator(createInput());
      expect(result.continue).toBe(true);
    });
  });

  // -------------------------------------------------------------------------
  // #976: summary uses last_assistant_message
  // -------------------------------------------------------------------------

  describe('summary from last_assistant_message (#976)', () => {
    it('uses last_assistant_message for summary when available', () => {
      const input = createInput({
        last_assistant_message: 'I refactored the auth module to use JWT tokens. All 15 tests pass.',
      });
      sessionHandoffGenerator(input);

      const yaml = getLatestYaml();
      expect(yaml).toContain('refactored the auth module');
    });

    it('truncates long messages at sentence boundary', () => {
      const longMsg = `First sentence here. ${'A '.repeat(200)}`;
      const input = createInput({ last_assistant_message: longMsg });
      sessionHandoffGenerator(input);

      const yaml = getLatestYaml();
      // Should have truncated, not the full message
      expect(yaml.length).toBeLessThan(longMsg.length + 200);
    });

    it('falls back to completed task name when no last_assistant_message', () => {
      const taskEntry = JSON.stringify({ task_subject: 'Fix login bug', task_status: 'completed' });
      mockExistsSync.mockImplementation((p: string) =>
        String(p).includes('task-completions.jsonl'),
      );
      mockReadFileSync.mockReturnValue(`${taskEntry}\n`);

      const input = createInput();
      sessionHandoffGenerator(input);

      const yaml = getLatestYaml();
      expect(yaml).toContain('Fix login bug');
    });

    it('falls back to generic stats when no message and no tasks', () => {
      const input = createInput();
      sessionHandoffGenerator(input);

      const yaml = getLatestYaml();
      expect(yaml).toContain('tool calls');
    });
  });

  // -------------------------------------------------------------------------
  // #976: deriveStatus uses last_assistant_message
  // -------------------------------------------------------------------------

  describe('status from last_assistant_message (#976)', () => {
    it('detects "completed" from message when no task log', () => {
      const input = createInput({
        last_assistant_message: 'All done. Everything is working correctly.',
      });
      // Simulate some tool usage so it's not "interrupted"
      mockExistsSync.mockImplementation((p: string) =>
        String(p).includes('metrics.json'),
      );
      mockReadFileSync.mockReturnValue(JSON.stringify({ tools: { Bash: 5 } }));

      sessionHandoffGenerator(input);
      const yaml = getLatestYaml();
      expect(yaml).toContain('status: completed');
    });

    it('detects "completed" from "finished" keyword', () => {
      mockExistsSync.mockImplementation((p: string) =>
        String(p).includes('metrics.json'),
      );
      mockReadFileSync.mockReturnValue(JSON.stringify({ tools: { Read: 3 } }));

      const input = createInput({
        last_assistant_message: 'I finished implementing the feature.',
      });
      sessionHandoffGenerator(input);
      const yaml = getLatestYaml();
      expect(yaml).toContain('status: completed');
    });

    it('returns "interrupted" when no tools used', () => {
      const input = createInput();
      sessionHandoffGenerator(input);
      const yaml = getLatestYaml();
      expect(yaml).toContain('status: interrupted');
    });

    it('returns "partial" when pending tasks exist', () => {
      const taskEntry = JSON.stringify({ task_subject: 'Remaining work', task_status: 'in_progress' });
      mockExistsSync.mockImplementation((p: string) => {
        if (String(p).includes('task-completions.jsonl')) return true;
        if (String(p).includes('metrics.json')) return true;
        return false;
      });
      mockReadFileSync.mockImplementation((p: string) => {
        if (String(p).includes('task-completions')) return `${taskEntry}\n`;
        return JSON.stringify({ tools: { Bash: 2 } });
      });

      const input = createInput({ last_assistant_message: 'All done.' });
      sessionHandoffGenerator(input);
      const yaml = getLatestYaml();
      // pending tasks override message-based completion
      expect(yaml).toContain('status: partial');
    });
  });

  // -------------------------------------------------------------------------
  // #976: next_steps from last_assistant_message
  // -------------------------------------------------------------------------

  describe('next_steps from last_assistant_message (#976)', () => {
    it('extracts next steps from markdown bullet list', () => {
      const msg = `Done with the refactor.\n\nNext steps:\n- Run integration tests\n- Deploy to staging\n- Update docs\n`;
      const input = createInput({ last_assistant_message: msg });
      sessionHandoffGenerator(input);

      const yaml = getLatestYaml();
      expect(yaml).toContain('Run integration tests');
      expect(yaml).toContain('Deploy to staging');
      expect(yaml).toContain('Update docs');
    });

    it('limits to 3 next steps', () => {
      const msg = `Next steps:\n- A\n- B\n- C\n- D\n- E\n`;
      const input = createInput({ last_assistant_message: msg });
      sessionHandoffGenerator(input);

      const yaml = getLatestYaml();
      expect(yaml).toContain('A');
      expect(yaml).toContain('C');
      expect(yaml).not.toContain('"D"');
    });

    it('prefers pending tasks over message-extracted next steps', () => {
      const taskEntry = JSON.stringify({ task_subject: 'Fix tests', task_status: 'pending' });
      mockExistsSync.mockImplementation((p: string) =>
        String(p).includes('task-completions.jsonl'),
      );
      mockReadFileSync.mockReturnValue(`${taskEntry}\n`);

      const msg = `Next steps:\n- Something from message\n`;
      const input = createInput({ last_assistant_message: msg });
      sessionHandoffGenerator(input);

      const yaml = getLatestYaml();
      expect(yaml).toContain('Fix tests');
    });

    it('falls back to branch hint when no message and no pending tasks', () => {
      const input = createInput();
      sessionHandoffGenerator(input);

      const yaml = getLatestYaml();
      expect(yaml).toContain('Continue work on branch feat/test-branch');
    });
  });
});
